        key: p.key,
        name: p.name || prettyKey(p.key),
        kind: p.kind || '',
        status: p.status,
        uptime: p.uptime_pct,
        error_rate: p.error_rate,
        p95: p.latency_p95_ms,
        p50: p.latency_p50_ms,
        checked: p.checked_at,
